-- ============================================================
-- Bright Hermosa Realty — site_content setup
-- Run this in the Supabase Dashboard > SQL Editor.
-- Creates the table used by the Home / About / Contact page
-- editors and seeds it with the current website content.
-- Safe to re-run: re-seeding overwrites the three rows with
-- the content embedded in this file.
-- ============================================================

-- 1. Table
create table if not exists public.site_content (
  id text primary key,          -- 'home' | 'about' | 'contact'
  content jsonb not null,       -- full page content object
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

-- 2. Row Level Security
alter table public.site_content enable row level security;

drop policy if exists "Public read site content" on public.site_content;
drop policy if exists "Public insert site content" on public.site_content;
drop policy if exists "Public update site content" on public.site_content;

-- Anyone can read (the public website needs this).
create policy "Public read site content" on public.site_content
  for select using (true);

-- NOTE: these write policies allow anonymous writes so the admin
-- app's offline/demo login keeps working. To lock writes down to
-- real Supabase accounts, replace "true" in the two policies below
-- with: (auth.role() = 'authenticated')
create policy "Public insert site content" on public.site_content
  for insert with check (true);

create policy "Public update site content" on public.site_content
  for update using (true) with check (true);

-- 3. Seed with the current website content
insert into public.site_content (id, content)
values ('home', $site_content_json${"hero":{"image":"","imageKey":"falls","title":"Bright places. Beautiful possibilities.","subtitle":"A clear, premium identity for every property touchpoint. Your Best Property Investment Starts Here.","primaryCta":"View Properties","secondaryCta":"Learn More"},"featured":{"label":"Featured","title":"Premium Leisure Communities"},"whyChooseUs":{"label":"Why Choose Us","title":"A modern real estate brand with warmth and confidence.","description":"This identity system balances the trust of an established realty company with the clarity and energy expected by today's property buyers.","features":[{"icon":"forum","title":"Communication","desc":"Experience seamless communication where clear channels promote collaboration and understanding."},{"icon":"verified","title":"Reliability","desc":"Trust in unwavering reliability. With a steadfast commitment to quality and consistency, we deliver on our promises."},{"icon":"location_on","title":"Prime Location","desc":"Discover unparalleled convenience with strategic positioning offering easy access to key destinations."}],"image":"https://lh3.googleusercontent.com/aida-public/AB6AXuBcz4ZJKb6HP1nh3jM4LnWgsMyIOApmPTbvmQ3JqeZFvl9clo36R-rYpAfrBAExluuMKr-e2BBaGSTEzjZyFs_RR21vzbU4N7QErlrXZSLE9WU-X4jnz5pVgnGOKz3DrTaiMBkqJxrNOHM6TDYc44PgJSyIL7nelgmA1JBINfm8lFEXltDZ3GZIupzozNm370xBLv3HzA1HqPxcHY8QQvLWTPPNriFyW2xGlcYnnrPwUf5ocFnJTxWdRY0Ajf5ZpdOjZGo-13o6458","card":{"title":"Sustainable Growth","subtitle":"Harmonious with nature"}},"mission":{"title":"Mission","text":"To guide clients toward property opportunities with clarity, integrity, and attentive service - helping them make confident decisions and create lasting value.","direction":"DIRECTION: TRUST / SERVICE / VALUE"},"vision":{"title":"Vision","text":"To become a trusted Philippine real estate brand known for beautiful places, responsible growth, and relationships that endure.","direction":"DIRECTION: PLACE / PROGRESS / PARTNERSHIP"},"cta":{"title":"Ready to Invest?","text":"Begin your journey here and explore the best property investments.","button":"Contact Our Specialists"}}$site_content_json$::jsonb)
on conflict (id) do update
  set content = excluded.content,
      updated_at = now();

insert into public.site_content (id, content)
values ('about', $site_content_json${"aboutIntro":{"title":"About Us","paragraphs":["Bright Hermosa Realty Inc. is a real estate development established in 2022 devoted to building leisure farm communities that provide the best modern luxurious amenities in rural facilities for clients who wish to have a resort-like leisure farm lot away from the pollution, fast-paced lifestyle, and noise present in metropolitan areas.​","As much as we want to have the best leisure farm and resort communities, our company believes in sustainability, thus creating real estate developments synchronizing and adapting within nature."],"image":"https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&w=800&q=80"},"hero":{"title":"Buy Smart. Sell Wise.","text":"Bright Hermosa Realty Inc. is a real estate company committed to helping individuals, families, and investors make confident and informed property decisions.","image":"https://lh3.googleusercontent.com/aida-public/AB6AXuAmid-NnETpuc4Tbi-Wx2wk0M5C9qdF5m3YZ7w3JdmlZQ_WoNBRmy7HSYuOhSYEDT0_BYBhAgl08WelLOXZcBnxcVztSby8iYTvUKx6o-rRrV7YXaclaUIaJwpIhEjFZ-v7jqDNxUtf7LUY-8EQSxLHlyBF6RJ2LFWnC902WwgU-ROq2ZuMXc-vAbAUb5cC8hQ6tCb5inAcYlTRAPJHMWufF-pqup011L8LkPg5VYkBP0wWyfx5ghDAG8R1zuXRGts9_M3RQ8dqK9w"},"mission":{"title":"Mission","text":"To guide clients toward property opportunities with clarity, integrity, and attentive service - helping them make confident decisions and create lasting value.","tagline":"SERVICE / TRANSPARENCY / CONFIDENCE"},"vision":{"title":"Vision","text":"To become a trusted Philippine real estate brand known for beautiful places, responsible growth, and relationships that endure.","tagline":"TRUST / GROWTH / OPPORTUNITY"},"coreNarrative":{"title":"Our Core Narrative","paragraphs":["We understand that real estate is more than just a transaction—it is about finding a place to call home, securing your family’s future, or growing your investment portfolio.","Our team provides professional guidance through every step of the process, ensuring that our clients are well-informed and empowered to make the best possible choices.","Whether you are looking for a residential property, a productive farm lot, or a strategic commercial space, Bright Hermosa Realty Inc. is here to connect you with opportunities that align with your vision."],"image":"https://lh3.googleusercontent.com/aida-public/AB6AXuDpBFV3pb8_F9cqqCXeFgmHaUEJSLW2Kg4M9tm75eM_kYgwWkATnANDEACYQh5FAgttJUe0_3i_gEhHeo0wquHQDFUH6Xb2mH4IHwxkR8E33p9IFhLFclZPPzI0Q2l7ihdv0-6548kT2amowoniRfxf56fGImk67gO3iztDcxTxOnduiHt2YFRwhl5pkk07gijfQZBPRk73Vo_HjGYjNhZE987wPwoiB1TIGICOWPNJxOeWwec1_p77ICvveMkBTef8-DRIY8DWBNy5Tg"},"coreCommitment":{"title":"Our Core Commitment","paragraphs":["We are committed to delivering a real estate experience built on trust, transparency, professionalism, and genuine customer care. From the initial inquiry and property presentation to site visits, documentation, and closing, our team works closely with every client to make the process as clear, organized, and convenient as possible.","We do not simply offer properties. We help our clients understand their options, recognize opportunities, and choose properties that support their present needs and long-term plans."],"image":"https://lh3.googleusercontent.com/aida-public/AB6AXuAgs0JPUzTZBGshuFqgdP5KE5gn-8YPTO9ahpkB__3DA014lZjM52neCPXogT4wAnBypRHCx9I7xy73Q8-CcVRfLkcWi-nJqLr6wu4z8moU_p0q6f_J2DMu-FofABvs3wbHsRzqEysrLVReeNzhE_HQlfSkwVLxiOwF_j_GQYBt1h89zMw7wU664XBsUTfoMB2Xv1QkxTRxrgS9KiI25mDDcOCiOmlmlhnFSR-7mSsVarknVfscvqrEJoORfWPucM-EGHV5arRufOk"},"board":{"title":"Board of Directors","subtitle":"The leadership team steering Bright Hermosa Realty Inc. toward its mission and vision.","members":[{"image":"","imageKey":"chairman","name":"Hernando B. signo","position":"Chairman of the Board","desc":"Our Chairman brings a distinguished background in the maritime industry, having risen to the rank of Second Officer and Dynamic Positioning Officer (DPO). Following his maritime career, he entered the real estate industry as an agent and subsequently advanced into investment, collaborating with prominent industry stakeholders. This experience enabled him to recognize the strong growth potential and strategic opportunities within the real estate sector."},{"image":"","imageKey":"president","name":"Atty. Adrian Carlo Uy Escay","position":"President & CEO","desc":"Our esteemed President, brings a distinguished multidisciplinary background and extensive professional experience to the organization. His career spans engineering, business, real estate, and legal practice, with particular expertise in civil and business law. A graduate of San Beda College of Law, he continues to provide strong leadership, strategic insight, and sound legal perspective to the company."},{"image":"","imageKey":"vicePresident","name":"Richard Mapusao, REB, REA","position":"Vice President","desc":"Our Vice President, Mr. Mapusao, is a licensed Real Estate Broker and Appraiser who brings extensive expertise and experience to the organization. Prior to his current role, he served as a mathematics professor at a prestigious institution in Tagaytay City for 20 years. His strong academic background and real estate credentials make him a valuable asset to our leadership team."}]},"offices":{"title":"Our Offices","subtitle":"Visit us in person, our doors are always open to guide you through your next property move.","items":[{"image":"","imageKey":"salesOfficeRTE","name":"Sales Office - Royale Tagaytay Estates","address":"Royale Tagaytay Estates Alfonso Rd., Alfonso, Cavite","contact":"+63 917 162 6920"},{"image":"","imageKey":"salesOfficeMVLC","name":"Sales Office - Mountain View Leisure Community","address":"Mountain View Leisure Community Munting lndang, Nasugbu, Batangas","contact":"+63 995 673 1952"}]},"events":{"title":"Company Events","subtitle":"Moments from our milestones, launches, and community engagements.","items":[{"image":"","imageKey":"headOffice"},{"image":"","imageKey":"salesOfficeMVLC"},{"image":"","imageKey":"salesOfficeRTE"},{"image":"","imageKey":"subsidiaryOffice"},{"image":"","imageKey":"salesOfficeRTE"},{"image":"","imageKey":"salesOfficeRTE"}]},"coreValues":{"title":"Core Values","subtitle":"The principles that guide our every interaction and development.","items":[{"icon":"verified","title":"Integrity","desc":"We operate with honesty and transparency in all our dealings, ensuring that our clients can trust us with their important real estate decisions."},{"icon":"person","title":"Client-Focused","desc":"We prioritize the needs and goals of our clients, providing personalized service and attentive support throughout their real estate journey."},{"icon":"handshake","title":"Reliability","desc":"We are a dependable partner that our clients can count on for accurate information, timely responses, and professional advice."},{"icon":"workspace_premium","title":"Excellence","desc":"We strive for the highest standards in everything we do, from the properties we offer to the quality of service we provide."},{"icon":"business_center","title":"Professionalism","desc":"We conduct ourselves with the utmost professionalism, maintaining a high level of expertise and ethical conduct in all our interactions."}]},"whyChooseUs":{"title":"Why Choose Us?","subtitle":"Discover the Bright Hermosa difference in every property journey.","reasons":["Personalized property recommendations.","Clear and accurate information for informed decisions.","Access to a diverse range of valuable property opportunities.","Professional guidance through every step of the process.","Reliable and transparent communication.","Commitment to helping you find the right property.","Support in achieving your long-term real estate goals."]},"sustainability":{"title":"Commitment to Sustainability","paragraphs":["At Bright Hermosa, we are stewards of the land. Our mission is to harness the inherent beauty of the environment, creating sustainable developments that seamlessly integrate with and enhance the natural world.","We are driven by a commitment to responsible land development, ensuring the preservation of the earth's intrinsic allure. Through innovative design, eco-conscious construction, and sustainable practices, we aspire to redefine high-end living."],"image":"https://lh3.googleusercontent.com/aida-public/AB6AXuAud62F428PKFUZ45vS_sQ2i42V6n6OY7F2QHGdfrzwTANr-lmTsV-i00U91SvPTZksjQBKkQQDk4OupdZIjaaCfDXeff0tMhB0vXcp__Q_RGqZMZ_97MC27RWJaHRoqz0WlUIX8kvFvfRygXbv5yCgA0o3PmzW9B2EGdYIsHstrpE_uVH6x3IgUs9JKz9uv-VND8eWIMuAAsaYT7EmMWxEQqX4fSiAZudE5ZFjoOwMGO4PlFpWD-NMYksp33cFJaIirxu1vHO5ilg"},"departments":{"title":"Company Departments","subtitle":"Our specialized divisions collaborating to provide seamless land investment, legal compliance, and community development.","items":[{"name":"IMET","desc":"IMET drives the company’s digital innovation, creative marketing, technology solutions, and online communication strategies to strengthen brand presence and support business growth.","image":"https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=800&q=80"},{"name":"Sales and Operations","desc":"Sales and Operations manages client engagement, property sales, documentation, and day-to-day processes to ensure smooth transactions and excellent customer service.","image":"https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=800&q=80"},{"name":"Administration","desc":"Administration supports the organization by managing office operations, employee coordination, records, resources, and internal processes to maintain an efficient workplace.","image":"https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=800&q=80"}]}}$site_content_json$::jsonb)
